 20→const PHASE_PROMPTS: Record<Phase, string> = {
 21→  spec: "Review GitHub issue #{issue} and create an implementation plan with verification criteria. Run the /spec {issue} workflow.",
 22→  "security-review":
 23→    "Perform a deep security analysis for GitHub issue #{issue} focusing on auth, permissions, and sensitive operations. Run the /security-review {issue} workflow.",
 24→  testgen:
 25→    "Generate test stubs for GitHub issue #{issue} based on the specification. Run the /testgen {issue} workflow.",
 26→  exec: "Implement the feature for GitHub issue #{issue} following the spec. Run the /exec {issue} workflow.",
 27→  test: "Execute structured browser-based testing for GitHub issue #{issue}. Run the /test {issue} workflow.",
 28→  qa: "Review the implementation for GitHub issue #{issue} against acceptance criteria. Run the /qa {issue} workflow.",
 29→  loop: "Parse test/QA findings for GitHub issue #{issue} and iterate until quality gates pass. Run the /loop {issue} workflow.",
 30→};
 31→
 32→/**
 33→ * Phases that require worktree isolation (exec, test, qa)
 34→ * Spec runs in main repo since it's planning-only
 35→ */
 36→const ISOLATED_PHASES: Phase[] = ["exec", "test", "qa"];
 37→
 38→/**
 39→ * Cold-start retry threshold in seconds.
 40→ * Failures under this duration are likely Claude Code subprocess initialization
 41→ * issues rather than genuine phase failures (based on empirical data: cold-start
 42→ * failures consistently complete in 15-39s vs 150-310s for real work).
 43→ */
 44→const COLD_START_THRESHOLD_SECONDS = 60;
 45→const COLD_START_MAX_RETRIES = 2;
 46→
 47→export function parseQaVerdict(output: string): QaVerdict | null {
 48→  if (!output) return null;
 49→
 50→  // Match various verdict formats:
 51→  // - "### Verdict: X" (markdown header)
 52→  // - "**Verdict:** X" (bold label with colon inside)
 53→  // - "**Verdict:** **X**" (bold label and bold value)
 54→  // - "Verdict: X" (plain)
 55→  // Case insensitive, handles optional markdown formatting
 56→  const verdictMatch = output.match(
 57→    /(?:###?\s*)?(?:\*\*)?Verdict:?\*?\*?\s*\*?\*?\s*(READY_FOR_MERGE|AC_MET_BUT_NOT_A_PLUS|AC_NOT_MET|NEEDS_VERIFICATION)\*?\*?/i,
 58→  );
 59→
 60→  if (!verdictMatch) return null;
 61→
 62→  // Normalize to uppercase with underscores
 63→  const verdict = verdictMatch[1].toUpperCase().replace(/-/g, "_") as QaVerdict;
 64→  return verdict;
 65→}
 66→
 67→/**
 68→ * Format duration in human-readable format
 69→ */
 70→export function formatDuration(seconds: number): string {
 71→  if (seconds < 60) {
 72→    return `${seconds.toFixed(1)}s`;
 73→  }
 74→  const mins = Math.floor(seconds / 60);
 75→  const secs = seconds % 60;
 76→  return `${mins}m ${secs.toFixed(0)}s`;
 77→}
 78→
 79→/**
 80→ * Get the prompt for a phase with the issue number substituted
 81→ */
 82→function getPhasePrompt(phase: Phase, issueNumber: number): string {
 83→  return PHASE_PROMPTS[phase].replace(/\{issue\}/g, String(issueNumber));
 84→}
 85→
 86→/**
 87→ * Execute a single phase for an issue using Claude Agent SDK
 88→ */
 89→async function executePhase(
 90→  issueNumber: number,
 91→  phase: Phase,
 92→  config: ExecutionConfig,
 93→  sessionId?: string,
 94→  worktreePath?: string,
 95→  shutdownManager?: ShutdownManager,
 96→  spinner?: PhaseSpinner,
 97→): Promise<PhaseResult & { sessionId?: string }> {
 98→  const startTime = Date.now();
 99→
100→  if (config.dryRun) {
101→    // Dry run - just simulate
102→    if (config.verbose) {
103→      console.log(chalk.gray(`    Would execute: /${phase} ${issueNumber}`));
104→    }
105→    return {
106→      phase,
107→      success: true,
108→      durationSeconds: 0,
109→    };
110→  }
111→
112→  const prompt = getPhasePrompt(phase, issueNumber);
113→
114→  if (config.verbose) {
115→    console.log(chalk.gray(`    Prompt: ${prompt}`));
116→    if (worktreePath && ISOLATED_PHASES.includes(phase)) {
117→      console.log(chalk.gray(`    Worktree: ${worktreePath}`));
118→    }
119→  }
120→
121→  // Determine working directory and environment
122→  const shouldUseWorktree = worktreePath && ISOLATED_PHASES.includes(phase);
123→  const cwd = shouldUseWorktree ? worktreePath : process.cwd();
124→
125→  // Track stderr for error diagnostics (declared outside try for catch access)
126→  let capturedStderr = "";
127→
128→  try {
129→    // Check if shutdown is in progress
130→    if (shutdownManager?.shuttingDown) {
131→      return {
132→        phase,
133→        success: false,
134→        durationSeconds: 0,
135→        error: "Shutdown in progress",
136→      };
137→    }
138→
139→    // Create abort controller for timeout
140→    const abortController = new AbortController();
141→    const timeoutId = setTimeout(() => {
142→      abortController.abort();
143→    }, config.phaseTimeout * 1000);
144→
145→    // Register abort controller with shutdown manager for graceful shutdown
146→    if (shutdownManager) {
147→      shutdownManager.setAbortController(abortController);
148→    }
149→
150→    let resultSessionId: string | undefined;
151→    let resultMessage: SDKResultMessage | undefined;
152→    let lastError: string | undefined;
153→    let capturedOutput = "";
154→
155→    // Build environment with worktree isolation variables
156→    const env: Record<string, string> = {
157→      ...process.env,
158→      CLAUDE_HOOKS_SMART_TESTS: config.noSmartTests ? "false" : "true",
159→    };
160→
161→    // Set worktree isolation environment variables
162→    if (shouldUseWorktree) {
163→      env.SEQUANT_WORKTREE = worktreePath;
164→      env.SEQUANT_ISSUE = String(issueNumber);
165→    }
166→
167→    // Set orchestration context for skills to detect they're part of a workflow
168→    // Skills can check these to skip redundant pre-flight checks
169→    env.SEQUANT_ORCHESTRATOR = "sequant-run";
170→    env.SEQUANT_PHASE = phase;
171→
172→    // Execute using Claude Agent SDK
173→    // Note: Don't resume sessions when switching to worktree (different cwd breaks resume)
174→    const canResume = sessionId && !shouldUseWorktree;
175→
176→    // Get MCP servers config if enabled
177→    // Reads from Claude Desktop config and passes to SDK for headless MCP support
178→    const mcpServers = config.mcp ? getMcpServersConfig() : undefined;
179→
180→    // Track whether we're actively streaming verbose output
181→    // Pausing spinner once per streaming session prevents truncation from rapid pause/resume cycles
182→    // (Issue #283: ora's stop() clears the current line, which can truncate output when
183→    // pause/resume is called for every chunk in rapid succession)
184→    let verboseStreamingActive = false;
185→
186→    const queryInstance = query({
187→      prompt,
188→      options: {
189→        abortController,
190→        cwd,
191→        // Load project settings including skills
192→        settingSources: ["project"],
193→        // Use Claude Code's system prompt and tools
194→        systemPrompt: { type: "preset", preset: "claude_code" },
195→        tools: { type: "preset", preset: "claude_code" },
196→        // Bypass permissions for headless execution
197→        permissionMode: "bypassPermissions",
198→        allowDangerouslySkipPermissions: true,
199→        // Resume from previous session if provided (but not when switching directories)
200→        ...(canResume ? { resume: sessionId } : {}),
201→        // Configure smart tests and worktree isolation via environment
202→        env,
203→        // Pass MCP servers for headless mode (AC-2)
204→        ...(mcpServers ? { mcpServers } : {}),
205→        // Capture stderr for debugging (helps diagnose early exit failures)
206→        stderr: (data: string) => {
207→          capturedStderr += data;
208→          // Write stderr in verbose mode
209→          if (config.verbose) {
210→            // Pause spinner once to avoid truncation (Issue #283)
211→            if (!verboseStreamingActive) {
212→              spinner?.pause();
213→              verboseStreamingActive = true;
214→            }
215→            process.stderr.write(chalk.red(data));
216→          }
217→        },
218→      },
219→    });
220→
221→    // Stream and process messages
222→    for await (const message of queryInstance) {
223→      // Capture session ID from system init message
224→      if (message.type === "system" && message.subtype === "init") {
225→        resultSessionId = message.session_id;
226→      }
227→
228→      // Capture output from assistant messages
229→      if (message.type === "assistant") {
230→        // Extract text content from the message
231→        const content = message.message.content as Array<{
232→          type: string;
233→          text?: string;
234→        }>;
235→        const textContent = content
236→          .filter((c) => c.type === "text" && c.text)
237→          .map((c) => c.text)
238→          .join("");
239→        if (textContent) {
240→          capturedOutput += textContent;
241→          // Show streaming output in verbose mode
242→          if (config.verbose) {
243→            // Pause spinner once at start of streaming to avoid truncation
244→            // (Issue #283: repeated pause/resume causes ora to clear lines between chunks)
245→            if (!verboseStreamingActive) {
246→              spinner?.pause();
247→              verboseStreamingActive = true;
248→            }
249→            process.stdout.write(chalk.gray(textContent));
250→          }
251→        }
252→      }
253→
254→      // Capture the final result
255→      if (message.type === "result") {
256→        resultMessage = message;
257→      }
258→    }
259→
260→    // Resume spinner after streaming completes (if we paused it)
261→    if (verboseStreamingActive) {
262→      spinner?.resume();
263→      verboseStreamingActive = false;
264→    }
265→
266→    clearTimeout(timeoutId);
267→
268→    // Clear abort controller from shutdown manager
269→    if (shutdownManager) {
270→      shutdownManager.clearAbortController();
271→    }
272→
273→    const durationSeconds = (Date.now() - startTime) / 1000;
274→
275→    // Check result status
276→    if (resultMessage) {
277→      if (resultMessage.subtype === "success") {
278→        // For QA phase, check the verdict to determine actual success
279→        // SDK "success" just means the query completed - we need to parse the verdict
280→        if (phase === "qa" && capturedOutput) {
281→          const verdict = parseQaVerdict(capturedOutput);
282→          // Only READY_FOR_MERGE and NEEDS_VERIFICATION are considered passing
283→          // NEEDS_VERIFICATION is external verification, not a code quality issue
284→          if (
285→            verdict &&
286→            verdict !== "READY_FOR_MERGE" &&
287→            verdict !== "NEEDS_VERIFICATION"
288→          ) {
289→            return {
290→              phase,
291→              success: false,
292→              durationSeconds,
293→              error: `QA verdict: ${verdict}`,
294→              sessionId: resultSessionId,
295→              output: capturedOutput,
296→              verdict, // Include parsed verdict
297→            };
298→          }
299→          // Pass case - include verdict for logging
300→          return {
301→            phase,
302→            success: true,
303→            durationSeconds,
304→            sessionId: resultSessionId,
305→            output: capturedOutput,
306→            verdict: verdict ?? undefined, // Include if found
307→          };
308→        }
309→
310→        return {
311→          phase,
312→          success: true,
313→          durationSeconds,
314→          sessionId: resultSessionId,
315→          output: capturedOutput,
316→        };
317→      } else {
318→        // Handle error subtypes
319→        const errorSubtype = resultMessage.subtype;
320→        if (errorSubtype === "error_max_turns") {
321→          lastError = "Max turns reached";
322→        } else if (errorSubtype === "error_during_execution") {
323→          lastError =
324→            resultMessage.errors?.join(", ") || "Error during execution";
325→        } else if (errorSubtype === "error_max_budget_usd") {
326→          lastError = "Budget limit exceeded";
327→        } else {
328→          lastError = `Error: ${errorSubtype}`;
329→        }
330→
331→        return {
332→          phase,
333→          success: false,
334→          durationSeconds,
335→          error: lastError,
336→          sessionId: resultSessionId,
337→        };
338→      }
339→    }
340→
341→    // No result message received
342→    return {
343→      phase,
344→      success: false,
345→      durationSeconds: (Date.now() - startTime) / 1000,
346→      error: "No result received from Claude",
347→      sessionId: resultSessionId,
348→    };
349→  } catch (err) {
350→    const durationSeconds = (Date.now() - startTime) / 1000;
351→    const error = err instanceof Error ? err.message : String(err);
352→
353→    // Check if it was an abort (timeout)
354→    if (error.includes("abort") || error.includes("AbortError")) {
355→      return {
356→        phase,
357→        success: false,
358→        durationSeconds,
359→        error: `Timeout after ${config.phaseTimeout}s`,
360→      };
361→    }
362→
363→    // Include stderr in error message if available (helps diagnose early exit failures)
364→    const stderrSuffix = capturedStderr
365→      ? `\nStderr: ${capturedStderr.slice(0, 500)}`
366→      : "";
367→
368→    return {
369→      phase,
370→      success: false,
371→      durationSeconds,
372→      error: error + stderrSuffix,
373→    };
374→  }
375→}
376→
377→/**
378→ * Execute a phase with automatic retry for cold-start failures and MCP fallback.
379→ *
380→ * Retry strategy:
381→ * 1. If phase fails within COLD_START_THRESHOLD_SECONDS, retry up to COLD_START_MAX_RETRIES times
382→ * 2. If still failing and MCP is enabled, retry once with MCP disabled (npx-based MCP servers
383→ *    can fail on first run due to cold-cache issues)
384→ *
385→ * The MCP fallback is safe because MCP servers are optional enhancements, not required
386→ * for core functionality.
387→ */
388→/**
389→ * @internal Exported for testing only
390→ */
391→export async function executePhaseWithRetry(
392→  issueNumber: number,
393→  phase: Phase,
394→  config: ExecutionConfig,
395→  sessionId?: string,
396→  worktreePath?: string,
397→  shutdownManager?: ShutdownManager,
398→  spinner?: PhaseSpinner,
399→  /** @internal Injected for testing — defaults to module-level executePhase */
400→  executePhaseFn: typeof executePhase = executePhase,
401→): Promise<PhaseResult & { sessionId?: string }> {
402→  // Skip retry logic if explicitly disabled
403→  if (config.retry === false) {
404→    return executePhaseFn(
405→      issueNumber,
406→      phase,
407→      config,
408→      sessionId,
409→      worktreePath,
410→      shutdownManager,
411→      spinner,
412→    );
413→  }
414→
415→  let lastResult: PhaseResult & { sessionId?: string };
416→
417→  // Phase 1: Cold-start retry attempts (with MCP enabled if configured)
418→  for (let attempt = 0; attempt <= COLD_START_MAX_RETRIES; attempt++) {
419→    lastResult = await executePhaseFn(
420→      issueNumber,
421→      phase,
422→      config,
423→      sessionId,
424→      worktreePath,
425→      shutdownManager,
426→      spinner,
427→    );
428→
429→    const duration = lastResult.durationSeconds ?? 0;
430→
431→    // Success or genuine failure (took long enough to be real work)
432→    if (lastResult.success || duration >= COLD_START_THRESHOLD_SECONDS) {
433→      return lastResult;
434→    }
435→
436→    // Cold-start failure detected — retry
437→    if (attempt < COLD_START_MAX_RETRIES) {
438→      if (config.verbose) {
439→        console.log(
440→          chalk.yellow(
441→            `\n    ⟳ Cold-start failure detected (${duration.toFixed(1)}s), retrying... (attempt ${attempt + 2}/${COLD_START_MAX_RETRIES + 1})`,
442→          ),
443→        );
444→      }
445→    }
446→  }
447→
448→  // Capture the original error for better diagnostics
449→  const originalError = lastResult!.error;
450→
451→  // Phase 2: MCP fallback - if MCP is enabled and we're still failing, try without MCP
452→  // This handles npx-based MCP servers that fail on first run due to cold-cache issues
453→  if (config.mcp && !lastResult!.success) {
454→    console.log(
455→      chalk.yellow(
456→        `\n    ⚠️ Phase failed with MCP enabled, retrying without MCP...`,
457→      ),
458→    );
459→
460→    // Create config copy with MCP disabled
461→    const configWithoutMcp: ExecutionConfig = {
462→      ...config,
463→      mcp: false,
464→    };
465→
466→    const retryResult = await executePhaseFn(
467→      issueNumber,
468→      phase,
469→      configWithoutMcp,
470→      sessionId,
471→      worktreePath,
472→      shutdownManager,
473→      spinner,
474→    );
475→
476→    if (retryResult.success) {
477→      console.log(
478→        chalk.green(
479→          `    ✓ Phase succeeded without MCP (MCP cold-start issue detected)`,
480→        ),
481→      );
482→      return retryResult;
483→    }
484→
485→    // Both attempts failed - return original error for better diagnostics
486→    return {
487→      ...lastResult!,
488→      error: originalError,
489→    };
490→  }
491→
492→  return lastResult!;
493→}
494→

