 12→import { spawnSync } from "child_process";
 13→import { LogWriter, createPhaseLogFromTiming } from "./log-writer.js";
 14→import { StateManager } from "./state-manager.js";
 15→import type { Phase as StatePhase } from "./state-schema.js";
 16→import { Phase, ExecutionConfig, PhaseResult, IssueResult } from "./types.js";
 17→import { ShutdownManager } from "../shutdown.js";
 18→import { PhaseSpinner } from "../phase-spinner.js";
