 36→export interface RunOptions {
 37→  phases?: string;
 38→  sequential?: boolean;
 39→  dryRun?: boolean;
 40→  verbose?: boolean;
 41→  timeout?: number;
 42→  logJson?: boolean;
 43→  noLog?: boolean;
 44→  logPath?: string;
 45→  qualityLoop?: boolean;
 46→  maxIterations?: number;
 47→  batch?: string[];
 48→  smartTests?: boolean;
 49→  noSmartTests?: boolean;
 50→  testgen?: boolean;
 51→  autoDetectPhases?: boolean;
 52→  /** Enable automatic worktree creation for issue isolation */
 53→  worktreeIsolation?: boolean;
 54→  /** Reuse existing worktrees instead of creating new ones */
 55→  reuseWorktrees?: boolean;
 56→  /** Suppress version warnings and non-essential output */
 57→  quiet?: boolean;
 58→  /** Chain issues: each branches from previous (requires --sequential) */
 59→  chain?: boolean;
 60→  /**
 61→   * Wait for QA pass before starting next issue in chain mode.
 62→   * When enabled, the chain pauses if QA fails, preventing downstream issues
 63→   * from building on potentially broken code.
 64→   */
 65→  qaGate?: boolean;
 66→  /**
 67→   * Base branch for worktree creation.
 68→   * Resolution priority: this CLI flag → settings.run.defaultBase → 'main'
 69→   */
 70→  base?: string;
 71→  /**
 72→   * Disable MCP servers in headless mode.
 73→   * When true, MCPs are not passed to the SDK (faster/cheaper runs).
 74→   * Resolution priority: this CLI flag → settings.run.mcp → default (true)
 75→   */
 76→  noMcp?: boolean;
 77→  /**
 78→   * Resume from last completed phase.
 79→   * Reads phase markers from GitHub issue comments and skips completed phases.
 80→   */
 81→  resume?: boolean;
 82→  /**
 83→   * Disable automatic retry with MCP fallback.
 84→   * When true, no retry attempts are made on phase failure.
 85→   * Useful for debugging to see the actual failure without retry masking it.
 86→   */
 87→  noRetry?: boolean;
 88→  /**
 89→   * Skip pre-PR rebase onto the base branch.
 90→   * When true, branches are not rebased before creating the PR.
 91→   * Use when you want to preserve branch state or handle rebasing manually.
 92→   */
 93→  noRebase?: boolean;
 94→  /**
 95→   * Skip PR creation after successful QA.
 96→   * When true, branches are pushed but no PR is created.
 97→   * Useful for manual workflows where PRs are created separately.
 98→   */
 99→  noPr?: boolean;
100→  /**
101→   * Force re-execution of issues even if they have completed status.
102→   * Bypasses the pre-flight state guard that skips ready_for_merge/merged issues.
103→   */
104→  force?: boolean;
105→  /**
106→   * Analyze run results and suggest workflow improvements.
107→   * Displays observations about timing patterns, phase mismatches, and
108→   * actionable suggestions after the summary output.
109→   */
110→  reflect?: boolean;
111→}
