139→/**
140→ * Parse dependencies from issue body and labels
141→ * Returns array of issue numbers this issue depends on
142→ */
143→export function parseDependencies(issueNumber: number): number[] {
144→  try {
145→    const result = spawnSync(
146→      "gh",
147→      ["issue", "view", String(issueNumber), "--json", "body,labels"],
148→      { stdio: "pipe" },
149→    );
150→
151→    if (result.status !== 0) return [];
152→
153→    const data = JSON.parse(result.stdout.toString());
154→    const dependencies: number[] = [];
155→
156→    // Parse from body: "Depends on: #123" or "**Depends on**: #123"
157→    if (data.body) {
158→      const bodyMatch = data.body.match(
159→        /\*?\*?depends\s+on\*?\*?:?\s*#?(\d+)/gi,
160→      );
161→      if (bodyMatch) {
162→        for (const match of bodyMatch) {
163→          const numMatch = match.match(/(\d+)/);
164→          if (numMatch) {
165→            dependencies.push(parseInt(numMatch[1], 10));
166→          }
167→        }
168→      }
169→    }
170→
171→    // Parse from labels: "depends-on/123" or "depends-on-123"
172→    if (data.labels && Array.isArray(data.labels)) {
173→      for (const label of data.labels) {
174→        const labelName = label.name || label;
175→        const labelMatch = labelName.match(/depends-on[-/](\d+)/i);
176→        if (labelMatch) {
177→          dependencies.push(parseInt(labelMatch[1], 10));
178→        }
179→      }
180→    }
181→
182→    return [...new Set(dependencies)]; // Remove duplicates
183→  } catch {
184→    return [];
185→  }
186→}
187→
188→/**
189→ * Sort issues by dependencies (topological sort)
190→ * Issues with no dependencies come first, then issues that depend on them
191→ */
192→export function sortByDependencies(issueNumbers: number[]): number[] {
193→  // Build dependency graph
194→  const dependsOn = new Map<number, number[]>();
195→  for (const issue of issueNumbers) {
196→    const deps = parseDependencies(issue);
197→    // Only include dependencies that are in our issue list
198→    dependsOn.set(
199→      issue,
200→      deps.filter((d) => issueNumbers.includes(d)),
201→    );
202→  }
203→
204→  // Topological sort using Kahn's algorithm
205→  const inDegree = new Map<number, number>();
206→  for (const issue of issueNumbers) {
207→    inDegree.set(issue, 0);
208→  }
209→  for (const deps of dependsOn.values()) {
210→    for (const dep of deps) {
211→      inDegree.set(dep, (inDegree.get(dep) || 0) + 1);
212→    }
213→  }
214→
215→  // Note: inDegree counts how many issues depend on each issue
216→  // We want to process issues that nothing depends on last
217→  // So we sort by: issues nothing depends on first, then dependent issues
218→  const sorted: number[] = [];
219→  const queue: number[] = [];
220→
221→  // Start with issues that have no dependencies
222→  for (const issue of issueNumbers) {
223→    const deps = dependsOn.get(issue) || [];
224→    if (deps.length === 0) {
225→      queue.push(issue);
226→    }
227→  }
228→
229→  const visited = new Set<number>();
230→  while (queue.length > 0) {
231→    const issue = queue.shift()!;
232→    if (visited.has(issue)) continue;
233→    visited.add(issue);
234→    sorted.push(issue);
235→
236→    // Find issues that depend on this one
237→    for (const [other, deps] of dependsOn.entries()) {
238→      if (deps.includes(issue) && !visited.has(other)) {
239→        // Check if all dependencies of 'other' are satisfied
240→        const allDepsSatisfied = deps.every((d) => visited.has(d));
241→        if (allDepsSatisfied) {
242→          queue.push(other);
243→        }
244→      }
245→    }
246→  }
247→
248→  // Add any remaining issues (circular dependencies or unvisited)
249→  for (const issue of issueNumbers) {
250→    if (!visited.has(issue)) {
251→      sorted.push(issue);
252→    }
253→  }
254→
255→  return sorted;
256→}
