298→export async function executeBatch(
299→  issueNumbers: number[],
300→  config: ExecutionConfig,
301→  logWriter: LogWriter | null,
302→  stateManager: StateManager | null,
303→  options: RunOptions,
304→  issueInfoMap: Map<number, { title: string; labels: string[] }>,
305→  worktreeMap: Map<number, WorktreeInfo>,
306→  shutdownManager?: ShutdownManager,
307→  packageManager?: string,
308→  baseBranch?: string,
309→): Promise<IssueResult[]> {
310→  const results: IssueResult[] = [];
311→
312→  for (const issueNumber of issueNumbers) {
313→    // Check if shutdown was triggered
314→    if (shutdownManager?.shuttingDown) {
315→      break;
316→    }
317→
318→    const issueInfo = issueInfoMap.get(issueNumber) ?? {
319→      title: `Issue #${issueNumber}`,
320→      labels: [],
321→    };
322→    const worktreeInfo = worktreeMap.get(issueNumber);
323→
324→    // Start issue logging
325→    if (logWriter) {
326→      logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
327→    }
328→
329→    const result = await runIssueWithLogging(
330→      issueNumber,
331→      config,
332→      logWriter,
333→      stateManager,
334→      issueInfo.title,
335→      issueInfo.labels,
336→      options,
337→      worktreeInfo?.path,
338→      worktreeInfo?.branch,
339→      shutdownManager,
340→      false, // Batch mode doesn't support chain
341→      packageManager,
342→      undefined,
343→      baseBranch,
344→    );
345→    results.push(result);
346→
347→    // Record PR info in log before completing issue
348→    if (logWriter && result.prNumber && result.prUrl) {
349→      logWriter.setPRInfo(result.prNumber, result.prUrl);
350→    }
351→
352→    // Complete issue logging
353→    if (logWriter) {
354→      logWriter.completeIssue();
355→    }
356→  }
357→
358→  return results;
359→}
