361→export async function runIssueWithLogging(
362→  issueNumber: number,
363→  config: ExecutionConfig,
364→  logWriter: LogWriter | null,
365→  stateManager: StateManager | null,
366→  issueTitle: string,
367→  labels: string[],
368→  options: RunOptions,
369→  worktreePath?: string,
370→  branch?: string,
371→  shutdownManager?: ShutdownManager,
372→  chainMode?: boolean,
373→  packageManager?: string,
374→  isLastInChain?: boolean,
375→  baseBranch?: string,
376→): Promise<IssueResult> {
377→  const startTime = Date.now();
378→  const phaseResults: PhaseResult[] = [];
379→  let loopTriggered = false;
380→  let sessionId: string | undefined;
381→
382→  console.log(chalk.blue(`\n  Issue #${issueNumber}`));
383→  if (worktreePath) {
384→    console.log(chalk.gray(`    Worktree: ${worktreePath}`));
385→  }
386→
387→  // Initialize state tracking for this issue
388→  if (stateManager) {
389→    try {
390→      const existingState = await stateManager.getIssueState(issueNumber);
391→      if (!existingState) {
392→        await stateManager.initializeIssue(issueNumber, issueTitle, {
393→          worktree: worktreePath,
394→          branch,
395→          qualityLoop: config.qualityLoop,
396→          maxIterations: config.maxIterations,
397→        });
398→      } else {
399→        // Update worktree info if it changed
400→        if (worktreePath && branch) {
401→          await stateManager.updateWorktreeInfo(
402→            issueNumber,
403→            worktreePath,
404→            branch,
405→          );
406→        }
407→      }
408→    } catch (error) {
409→      // State tracking errors shouldn't stop execution
410→      if (config.verbose) {
411→        console.log(chalk.yellow(`    ⚠️  State tracking error: ${error}`));
412→      }
413→    }
414→  }
415→
416→  // Determine phases for this specific issue
417→  let phases: Phase[];
418→  let detectedQualityLoop = false;
419→  let specAlreadyRan = false;
420→
421→  if (options.autoDetectPhases) {
422→    // Check if labels indicate a simple bug/fix (skip spec entirely)
423→    const lowerLabels = labels.map((l) => l.toLowerCase());
424→    const isSimpleBugFix = lowerLabels.some((label) =>
425→      BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
426→    );
427→
428→    if (isSimpleBugFix) {
429→      // Simple bug fix: skip spec, go straight to exec → qa
430→      phases = ["exec", "qa"];
431→      console.log(chalk.gray(`    Bug fix detected: ${phases.join(" → ")}`));
432→    } else {
433→      // Run spec first to get recommended workflow
434→      console.log(chalk.gray(`    Running spec to determine workflow...`));
435→
436→      // Create spinner for spec phase (1 of estimated 3: spec, exec, qa)
437→      const specSpinner = new PhaseSpinner({
438→        phase: "spec",
439→        phaseIndex: 1,
440→        totalPhases: 3, // Estimate; will be refined after spec
441→        shutdownManager,
442→      });
443→      specSpinner.start();
444→
445→      // Track spec phase start in state
446→      if (stateManager) {
447→        try {
448→          await stateManager.updatePhaseStatus(
449→            issueNumber,
450→            "spec",
451→            "in_progress",
452→          );
453→        } catch {
454→          // State tracking errors shouldn't stop execution
455→        }
456→      }
457→
458→      const specStartTime = new Date();
459→      // Note: spec runs in main repo (not worktree) for planning
460→      const specResult = await executePhaseWithRetry(
461→        issueNumber,
462→        "spec",
463→        config,
464→        sessionId,
465→        worktreePath, // Will be ignored for spec (non-isolated phase)
466→        shutdownManager,
467→        specSpinner,
468→      );
469→      const specEndTime = new Date();
470→
471→      if (specResult.sessionId) {
472→        sessionId = specResult.sessionId;
473→        // Update session ID in state for resume capability
474→        if (stateManager) {
475→          try {
476→            await stateManager.updateSessionId(
477→              issueNumber,
478→              specResult.sessionId,
479→            );
480→          } catch {
481→            // State tracking errors shouldn't stop execution
482→          }
483→        }
484→      }
485→
486→      phaseResults.push(specResult);
487→      specAlreadyRan = true;
488→
489→      // Log spec phase result
490→      // Note: Spec runs in main repo, not worktree, so no git diff stats
491→      if (logWriter) {
492→        const phaseLog = createPhaseLogFromTiming(
493→          "spec",
494→          issueNumber,
495→          specStartTime,
496→          specEndTime,
497→          specResult.success
498→            ? "success"
499→            : specResult.error?.includes("Timeout")
500→              ? "timeout"
501→              : "failure",
502→          { error: specResult.error },
503→        );
504→        logWriter.logPhase(phaseLog);
505→      }
506→
507→      // Track spec phase completion in state
508→      if (stateManager) {
509→        try {
510→          const phaseStatus = specResult.success ? "completed" : "failed";
511→          await stateManager.updatePhaseStatus(
512→            issueNumber,
513→            "spec",
514→            phaseStatus,
515→            {
516→              error: specResult.error,
517→            },
518→          );
519→        } catch {
520→          // State tracking errors shouldn't stop execution
521→        }
522→      }
523→
524→      if (!specResult.success) {
525→        specSpinner.fail(specResult.error);
526→        const durationSeconds = (Date.now() - startTime) / 1000;
527→        return {
528→          issueNumber,
529→          success: false,
530→          phaseResults,
531→          durationSeconds,
532→          loopTriggered: false,
533→        };
534→      }
535→
536→      specSpinner.succeed();
537→
538→      // Parse recommended workflow from spec output
539→      const parsedWorkflow = specResult.output
540→        ? parseRecommendedWorkflow(specResult.output)
541→        : null;
542→
543→      if (parsedWorkflow) {
544→        // Remove spec from phases since we already ran it
545→        phases = parsedWorkflow.phases.filter((p) => p !== "spec");
546→        detectedQualityLoop = parsedWorkflow.qualityLoop;
547→        console.log(
548→          chalk.gray(
549→            `    Spec recommends: ${phases.join(" → ")}${detectedQualityLoop ? " (quality loop)" : ""}`,
550→          ),
551→        );
552→      } else {
553→        // Fall back to label-based detection
554→        console.log(
555→          chalk.yellow(
556→            `    Could not parse spec recommendation, using label-based detection`,
557→          ),
558→        );
559→        const detected = detectPhasesFromLabels(labels);
560→        phases = detected.phases.filter((p) => p !== "spec");
561→        detectedQualityLoop = detected.qualityLoop;
562→        console.log(chalk.gray(`    Fallback: ${phases.join(" → ")}`));
563→      }
564→    }
565→  } else {
566→    // Use explicit phases with adjustments
567→    phases = determinePhasesForIssue(config.phases, labels, options);
568→    if (phases.length !== config.phases.length) {
569→      console.log(chalk.gray(`    Phases adjusted: ${phases.join(" → ")}`));
570→    }
571→  }
572→
573→  // Resume: filter out completed phases if --resume flag is set
574→  if (options.resume) {
575→    const resumeResult = filterResumedPhases(issueNumber, phases, true);
576→    if (resumeResult.skipped.length > 0) {
577→      console.log(
578→        chalk.gray(
579→          `    Resume: skipping completed phases: ${resumeResult.skipped.join(", ")}`,
580→        ),
581→      );
582→      phases = resumeResult.phases;
583→    }
584→    // Also skip spec if it was auto-detected as completed
585→    if (
586→      specAlreadyRan &&
587→      resumeResult.skipped.length === 0 &&
588→      resumeResult.phases.length === 0
589→    ) {
590→      console.log(chalk.gray(`    Resume: all phases already completed`));
591→    }
592→  }
593→
594→  // Add testgen phase if requested (and spec was in the phases)
595→  if (
596→    options.testgen &&
597→    (phases.includes("spec") || specAlreadyRan) &&
598→    !phases.includes("testgen")
599→  ) {
600→    // Insert testgen at the beginning if spec already ran, otherwise after spec
601→    if (specAlreadyRan) {
602→      phases.unshift("testgen");
603→    } else {
604→      const specIndex = phases.indexOf("spec");
605→      if (specIndex !== -1) {
606→        phases.splice(specIndex + 1, 0, "testgen");
607→      }
608→    }
609→  }
610→
611→  let iteration = 0;
612→  const useQualityLoop = config.qualityLoop || detectedQualityLoop;
613→  const maxIterations = useQualityLoop ? config.maxIterations : 1;
614→  let completedSuccessfully = false;
615→
616→  while (iteration < maxIterations) {
617→    iteration++;
618→
619→    if (useQualityLoop && iteration > 1) {
620→      console.log(
621→        chalk.yellow(
622→          `    Quality loop iteration ${iteration}/${maxIterations}`,
623→        ),
624→      );
625→      loopTriggered = true;
626→    }
627→
628→    let phasesFailed = false;
629→
630→    // Calculate total phases for progress indicator
631→    // If spec already ran in auto-detect mode, it's counted separately
632→    const totalPhases = specAlreadyRan ? phases.length + 1 : phases.length;
633→    const phaseIndexOffset = specAlreadyRan ? 1 : 0;
634→
635→    for (let phaseIdx = 0; phaseIdx < phases.length; phaseIdx++) {
636→      const phase = phases[phaseIdx];
637→      const phaseNumber = phaseIdx + 1 + phaseIndexOffset;
638→
639→      // Create spinner for this phase
640→      const phaseSpinner = new PhaseSpinner({
641→        phase,
642→        phaseIndex: phaseNumber,
643→        totalPhases,
644→        shutdownManager,
645→        iteration: useQualityLoop ? iteration : undefined,
646→      });
647→      phaseSpinner.start();
648→
649→      // Track phase start in state
650→      if (stateManager) {
651→        try {
652→          await stateManager.updatePhaseStatus(
653→            issueNumber,
654→            phase as StatePhase,
655→            "in_progress",
656→          );
657→        } catch {
658→          // State tracking errors shouldn't stop execution
659→        }
660→      }
661→
662→      const phaseStartTime = new Date();
663→      const result = await executePhaseWithRetry(
664→        issueNumber,
665→        phase,
666→        config,
667→        sessionId,
668→        worktreePath,
669→        shutdownManager,
670→        phaseSpinner,
671→      );
672→      const phaseEndTime = new Date();
673→
674→      // Capture session ID for subsequent phases
675→      if (result.sessionId) {
676→        sessionId = result.sessionId;
677→        // Update session ID in state for resume capability
678→        if (stateManager) {
679→          try {
680→            await stateManager.updateSessionId(issueNumber, result.sessionId);
681→          } catch {
682→            // State tracking errors shouldn't stop execution
683→          }
684→        }
685→      }
686→
687→      phaseResults.push(result);
688→
689→      // Log phase result with observability data (AC-1, AC-2, AC-3, AC-7)
690→      if (logWriter) {
691→        // Capture git diff stats for worktree phases (AC-1, AC-3)
692→        const diffStats = worktreePath
693→          ? getGitDiffStats(worktreePath, baseBranch)
694→          : undefined;
695→
696→        // Capture commit hash after phase (AC-2)
697→        const commitHash = worktreePath
698→          ? getCommitHash(worktreePath)
699→          : undefined;
700→
701→        // Read cache metrics for QA phase (AC-7)
702→        const cacheMetrics =
703→          phase === "qa" ? readCacheMetrics(worktreePath) : undefined;
704→
705→        const phaseLog = createPhaseLogFromTiming(
706→          phase,
707→          issueNumber,
708→          phaseStartTime,
709→          phaseEndTime,
710→          result.success
711→            ? "success"
712→            : result.error?.includes("Timeout")
713→              ? "timeout"
714→              : "failure",
715→          {
716→            error: result.error,
717→            verdict: result.verdict,
718→            // Observability fields (AC-1, AC-2, AC-3, AC-7)
719→            filesModified: diffStats?.filesModified,
720→            fileDiffStats: diffStats?.fileDiffStats,
721→            commitHash,
722→            cacheMetrics,
723→          },
724→        );
725→        logWriter.logPhase(phaseLog);
726→      }
727→
728→      // Track phase completion in state
729→      if (stateManager) {
730→        try {
731→          const phaseStatus = result.success
732→            ? "completed"
733→            : result.error?.includes("Timeout")
734→              ? "failed"
735→              : "failed";
736→          await stateManager.updatePhaseStatus(
737→            issueNumber,
738→            phase as StatePhase,
739→            phaseStatus,
740→            { error: result.error },
741→          );
742→        } catch {
743→          // State tracking errors shouldn't stop execution
744→        }
745→      }
746→
747→      if (result.success) {
748→        phaseSpinner.succeed();
749→      } else {
750→        phaseSpinner.fail(result.error);
751→        phasesFailed = true;
752→
753→        // If quality loop enabled, run loop phase to fix issues
754→        if (useQualityLoop && iteration < maxIterations) {
755→          // Create spinner for loop phase
756→          const loopSpinner = new PhaseSpinner({
757→            phase: "loop",
758→            phaseIndex: phaseNumber,
759→            totalPhases,
760→            shutdownManager,
761→            iteration,
762→          });
763→          loopSpinner.start();
764→
765→          const loopResult = await executePhaseWithRetry(
766→            issueNumber,
767→            "loop",
768→            config,
769→            sessionId,
770→            worktreePath,
771→            shutdownManager,
772→            loopSpinner,
773→          );
774→          phaseResults.push(loopResult);
775→
776→          if (loopResult.sessionId) {
777→            sessionId = loopResult.sessionId;
778→          }
779→
780→          if (loopResult.success) {
781→            loopSpinner.succeed();
782→            // Continue to next iteration
783→            break;
784→          } else {
785→            loopSpinner.fail(loopResult.error);
786→          }
787→        }
788→
789→        // Stop on first failure (if not in quality loop or loop failed)
790→        break;
791→      }
792→    }
793→
794→    // If all phases passed, exit the loop
795→    if (!phasesFailed) {
796→      completedSuccessfully = true;
797→      break;
798→    }
799→
800→    // If we're not in quality loop mode, don't retry
801→    if (!config.qualityLoop) {
802→      break;
803→    }
804→  }
805→
806→  const durationSeconds = (Date.now() - startTime) / 1000;
807→  // Success is determined by whether all phases completed in any iteration,
808→  // not whether all accumulated phase results passed (which would fail after loop recovery)
809→  const success = completedSuccessfully;
810→
811→  // Update final issue status in state
812→  if (stateManager) {
813→    try {
814→      const finalStatus = success ? "ready_for_merge" : "in_progress";
815→      await stateManager.updateIssueStatus(issueNumber, finalStatus);
816→    } catch {
817→      // State tracking errors shouldn't stop execution
818→    }
819→  }
820→
821→  // Create checkpoint commit in chain mode after QA passes
822→  if (success && chainMode && worktreePath) {
823→    createCheckpointCommit(worktreePath, issueNumber, config.verbose);
824→  }
825→
826→  // Rebase onto the base branch before PR creation (unless --no-rebase)
827→  // This ensures the branch is up-to-date and prevents lockfile drift
828→  // AC-1: Non-chain mode rebases onto the base branch before PR
829→  // AC-2: Chain mode rebases only the final branch onto the base branch before PR
830→  //        (intermediate branches must stay based on their predecessor)
831→  const shouldRebase =
832→    success &&
833→    worktreePath &&
834→    !options.noRebase &&
835→    (!chainMode || isLastInChain);
836→  if (shouldRebase) {
837→    rebaseBeforePR(
838→      worktreePath,
839→      issueNumber,
840→      packageManager,
841→      config.verbose,
842→      baseBranch,
843→    );
844→  }
845→
846→  // Create PR after successful QA + rebase (unless --no-pr)
847→  let prNumber: number | undefined;
848→  let prUrl: string | undefined;
849→  const shouldCreatePR = success && worktreePath && branch && !options.noPr;
850→  if (shouldCreatePR) {
851→    const prResult = createPR(
852→      worktreePath,
853→      issueNumber,
854→      issueTitle,
855→      branch,
856→      config.verbose,
857→      labels,
858→    );
859→    if (prResult.success && prResult.prNumber && prResult.prUrl) {
860→      prNumber = prResult.prNumber;
861→      prUrl = prResult.prUrl;
862→
863→      // Update workflow state with PR info
864→      if (stateManager) {
865→        try {
866→          await stateManager.updatePRInfo(issueNumber, {
867→            number: prResult.prNumber,
868→            url: prResult.prUrl,
869→          });
870→        } catch {
871→          // State tracking errors shouldn't stop execution
872→        }
873→      }
874→    }
875→  }
876→
877→  return {
878→    issueNumber,
879→    success,
880→    phaseResults,
881→    durationSeconds,
882→    loopTriggered,
883→    prNumber,
884→    prUrl,
885→  };
886→}
