  if (config.verbose) {
    console.log(chalk.gray(`    Prompt: ${prompt}`));
    if (worktreePath && ISOLATED_PHASES.includes(phase)) {
      console.log(chalk.gray(`    Worktree: ${worktreePath}`));
    }
